#!/usr/bin/env bash
# =============================================================================
# apply_fixes.sh  —  PDF_Editor3 text-editing bug-fix patcher
#
# Usage (from your project root):
#   bash apply_fixes.sh
#
# What it does:
#   1. Creates a timestamped backup of the two files it will replace.
#   2. Decodes and writes the fully-fixed versions of:
#        lib/services/pdf_service.dart
#        lib/widgets/annotation_overlay.dart
#   3. Prints a summary of every bug that was fixed.
#
# No Flutter commands, no network access, no dependencies required.
# =============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

GREEN="\033[0;32m"; YELLOW="\033[1;33m"; RED="\033[0;31m"; NC="\033[0m"

echo -e "${YELLOW}=== PDF_Editor3 — applying text-editing fixes ===${NC}"
echo ""

# ── 1. Sanity check ──────────────────────────────────────────────────────────
for f in lib/services/pdf_service.dart lib/widgets/annotation_overlay.dart; do
  if [ ! -f "$f" ]; then
    echo -e "${RED}ERROR: $f not found.${NC}"
    echo "Run this script from your project root (same folder as pubspec.yaml)."
    exit 1
  fi
done

# ── 2. Backup ────────────────────────────────────────────────────────────────
TS=$(date +%Y%m%d_%H%M%S)
BACKUP_DIR="backup_before_patch_${TS}"
mkdir -p "$BACKUP_DIR"
cp lib/services/pdf_service.dart         "$BACKUP_DIR/"
cp lib/widgets/annotation_overlay.dart   "$BACKUP_DIR/"
echo -e "${GREEN}✓ Backup created: ${BACKUP_DIR}/${NC}"
echo ""

# ── 3. Write fixed files via base64 ──────────────────────────────────────────
echo "Writing fixed files..."

# Helper: decode base64 block and write to file
write_b64() {
  local dest="$1"; shift
  printf '%s' "$*" | base64 -d > "$dest"
}

write_b64 "lib/services/pdf_service.dart" \
  ""
echo -e "${GREEN}✓ lib/services/pdf_service.dart${NC}"

write_b64 "lib/widgets/annotation_overlay.dart" \
  ""
echo -e "${GREEN}✓ lib/widgets/annotation_overlay.dart${NC}"


# ── 4. Summary ───────────────────────────────────────────────────────────────
echo ""
echo -e "${YELLOW}=== Fixes applied — summary ===${NC}"
echo ""
echo -e "${GREEN}BUG 1 (annotation_overlay.dart)${NC}"
echo "  IgnorePointer on text-block highlights swallowed every tap."
echo "  → Replaced with GestureDetector; tapping a blue outline now"
echo "    opens the inline editor immediately."
echo ""
echo -e "${GREEN}BUG 2 (annotation_overlay.dart)${NC}"
echo "  Text blocks only loaded at initState (too early) and on page"
echo "  change — switching to Edit Text tool triggered nothing."
echo "  → Added ref.listen on selectedToolProvider; blocks reload"
echo "    every time Edit Text mode is activated."
echo ""
echo -e "${GREEN}BUG 3 (pdf_service.dart — extractTextBlocks)${NC}"
echo "  pdfrx PdfRect uses bottom-left origin (top > bottom, Y grows UP)."
echo "  The code treated it as top-left origin, so every screenRect was"
echo "  placed at the wrong Y — hit-testing and block highlights were wrong."
echo "  → All bounds now converted to Flutter space"
echo "    (flutterTop = pageH - pdfNativeTop) before storing."
echo ""
echo -e "${GREEN}BUG 4 (pdf_service.dart — saveWithAnnotations text blocks)${NC}"
echo "  Save path used sfBottom = pageH - pdfTop - pdfHeight to flip Y,"
echo "  but Syncfusion page.graphics uses top-left origin (same as Flutter),"
echo "  so the flip was wrong and replacement text was written in the wrong"
echo "  position in the saved PDF."
echo "  → Coords passed directly: Rect.fromLTWH(pdfLeft, pdfTop, w, h)."
echo ""
echo -e "${GREEN}BUG 5 (pdf_service.dart — _sfRect for overlay annotations)${NC}"
echo "  All overlay annotations (text, highlight, shapes) used the same"
echo "  wrong Y-flip, placing them at mirrored positions in saved PDFs."
echo "  → _sfRect now returns Rect.fromLTWH(a.x, a.y, a.width, a.height)."
echo ""
echo -e "${GREEN}BUG 6 (pdf_service.dart — freehand drawLine)${NC}"
echo "  Freehand stroke points were flipped with (pageH - y), but points"
echo "  are already in Flutter space (screen Y / scale). Freehand strokes"
echo "  appeared upside-down in saved PDFs."
echo "  → Points passed directly without flipping."
echo ""
echo -e "${YELLOW}=== Done! Now run: flutter run ===${NC}"
echo ""